        for (int i = 3; i * i <= n; i += 2) {
            if (n % i == 0) return false;
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int R = sc.nextInt();
            int C = sc.nextInt();
            char[][] grid = new char[R][C];
            for (int i = 0; i < R; i++) {
                String s = sc.next();
                for (int j = 0; j < C; j++) {
                    grid[i][j] = s.charAt(j);
                }
            }
            int count = 0;
            for (int i = 0; i < R; i++) {
                for (int j = 0; j < C; j++) {
                    if (grid[i][j] == '#') continue;
                    int L = 0, R = 0, T = 0, B = 0;
                    for (int k = j - 1; k >= 0; k--) {
                        if (grid[i][k] == '^') L++;
                        else break;
                    }
                    for (int k = j + 1; k < C; k++) {
                        if (grid[i][k] == '^') R++;
                        else break;
                    }
                    for (int k = i - 1; k >= 0; k--) {
                        if (grid[k][j] == '^') T++;
                        else break;
                    }
                    for (int k = i + 1; k < R; k++) {
                        if (grid[k][j] == '^') B++;
                        else break;
                    }
                    int min = L;
                    if (R < min) min = R;
                    if (T < min) min = T;
                    if (B < min) min = B;
                    for (int k = 2; k <= min; k++) {
                        if (isPrime(k)) {
                            count++;
                            break;
                        }
                    }
                }
            }
            System.out.println(count);
        }
    }
}

